#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e5+5;
struct query{int l,r,id;}q[N];
int n,X,sq,a[N],m,L=1,R=0,c[N];
LL nowAns,ans[N];bitset<N> bt;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(query q1,query q2){
    if(q1.l/sq!=q2.l/sq)return q1.l<q2.l;
    if((q1.l/sq)&1)return q1.r<q2.r;else return q1.r>q2.r;
}
void Add(int p){
    c[a[p]]++;
    if(c[a[p]]==1)bt.set(a[p],0);return;
}
void Del(int p){
    c[a[p]]--;
    if(!c[a[p]])bt.set(a[p],1);return;
}
int main(){
    n=read(),m=read();sq=sqrt(n);
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<=m;i++)
        q[i].l=read(),q[i].r=read(),q[i].id=i;
    sort(q+1,q+m+1,cmp);bt.set();
    for(int i=1;i<=m;i++){
        while(L>q[i].l)Add(--L);
        while(R<q[i].r)Add(++R);
        while(L<q[i].l)Del(L++);
        while(R>q[i].r)Del(R--);
        ans[q[i].id]=bt._Find_first();
    }for(int i=1;i<=m;i++)cout<<ans[i]<<"\n";
    return 0;
}
